def _ensure_not_cancelled(value, _name: str = "") -> None:
    if value is CANCELLED:
        console.print("Cancelled.")
        raise SystemExit(0)


def _get_record_field(record: Any, key: str, default: Any = None) -> Any:
    """Get field from record whether it's a dict or object."""
    if isinstance(record, dict):
        return record.get(key, default)
    return getattr(record, key, default)
