@click.group(name="memory", context_settings=CONTEXT_SETTINGS)
@click.pass_context
def memory_group(ctx: click.Context) -> None:
    """Manage memories and memory operations.

    This command group provides operations for managing memories, memory records,
    sessions, and events in the GreenNode AgentBase platform.
    """
    ctx.ensure_object(dict)


def get_memory_client() -> MemoryClient:
    """Get a configured MemoryClient instance.
    
    Returns:
        MemoryClient instance with IAM credentials
    """
    try:
        iam_credentials = IAMCredentials()
        return MemoryClient(iam_credentials=iam_credentials)
    except Exception as e:
        console.print(f"[red]Error: Failed to initialize memory client: {e}[/red]")
        raise click.Abort()


def _prompt_strategy() -> Optional[LongTermMemoryStrategy]:
    """Prompt user for a single long-term memory strategy. Returns None if cancelled."""
    name_val = prompt_optional("Strategy name")
    if name_val is CANCELLED:
        return None
    type_val = prompt_field("Strategy type (e.g., default)", default="default")
    if type_val is CANCELLED:
        return None
    custom_prompt = prompt_optional("Custom fact extraction prompt")
    if custom_prompt is CANCELLED:
        return None
    namespace = prompt_field("Namespace template", default="default")
    if namespace is CANCELLED:
        return None
    enable_auto_s = prompt_field("Enable automatic memory record generation (true/false)", default="true")
    if enable_auto_s is CANCELLED:
        return None
    enable_auto = enable_auto_s.strip().lower() in ("true", "1", "yes", "y")
    return LongTermMemoryStrategy(
        name=name_val,
        type=type_val or None,
        custom_fact_extraction_prompt=custom_prompt,
        namespace_template=namespace or None,
        enable_automatic_memory_record_generation=enable_auto,
    )


# Memory CRUD operations
@memory_group.command(name="create")
@click.option("--name", "-n", required=False, default=None, help="Memory name")
@click.option("--description", "-d", required=False, default=None, help="Memory description")
@click.option("--event-expiry-duration", "-e", type=int, required=False, default=None, help="Event expiry duration in seconds (required)")
@click.option(
    "--strategy",
    "-S",
    "strategies",
    multiple=True,
    required=False,
    help='Long-term memory strategy as JSON, e.g. \'{"type":"default","namespaceTemplate":"ns1","enableAutomaticMemoryRecordGeneration":true}\'',
)
@click.option("--add-strategy", is_flag=True, help="Prompt to add long-term memory strategy interactively")
def create_memory(
    name: Optional[str],
    description: Optional[str],
    event_expiry_duration: Optional[int],
    strategies: tuple,
    add_strategy: bool,
) -> None:
    """Create a new memory with one or more long-term memory strategies.

    Examples:
        greennode memory create -n "My Memory" -d "Description" -e 3600
        greennode memory create -n "My Memory" -d "Description" -e 3600 -S '{"type":"default","namespaceTemplate":"default"}'
        greennode memory create -e 3600 --add-strategy   # interactive strategy
        greennode memory create   # interactive mode
    """
    name = prompt_if_missing(name, "Memory name")
    _ensure_not_cancelled(name, "name")
    description = prompt_if_missing(description, "Memory description")
    _ensure_not_cancelled(description, "description")
    event_expiry_s = prompt_if_missing(
        str(event_expiry_duration) if event_expiry_duration is not None else None,
        "Event expiry duration (seconds)",
        default="3600",
    )
    _ensure_not_cancelled(event_expiry_s, "event_expiry_duration")
    try:
        event_expiry_val = int(event_expiry_s)
    except ValueError:
        console.print("[red]Error: Event expiry duration must be an integer.[/red]")
        raise click.Abort()

    strategy_list: List[LongTermMemoryStrategy] = []
    for s in strategies:
        try:
            data = json.loads(s) if isinstance(s, str) else s
            strategy_list.append(LongTermMemoryStrategy(**data))
        except Exception as e:
            console.print(f"[red]Error: Invalid strategy JSON: {e}[/red]")
            raise click.Abort()

    if add_strategy or (not strategies and click.confirm("Add long-term memory strategy?", default=True)):
        console.print("[dim]Enter strategy details (empty or 'q' to finish adding strategies)[/dim]")
        while True:
            strat = _prompt_strategy()
            if strat is None:
                break
            strategy_list.append(strat)
            if not click.confirm("Add another strategy?", default=False):
                break

    try:
        client = get_memory_client()

        request_data: Any = {
            "name": name,
            "description": description,
            "eventExpiryDuration": event_expiry_val,
            "longTermMemoryStrategies": [s.model_dump(by_alias=True) for s in strategy_list],
        }

        request = MemoryCreateRequest(**request_data)

        result = run_async_with_cleanup(client, client.create_async(request=request))

        console.print(f"[green]✓ Memory created successfully with id: {result.id}[/green]")

    except Exception as e:
        console.print(f"[red]Error: Failed to create memory: {e}[/red]")
        raise click.Abort()


@memory_group.command(name="list")
def list_memories() -> None:
    """List all memories.

    Prompts for page and size (defaults 1, 10).

    Examples:
        greennode memory list
    """
    page_s = prompt_field("Page", default="1")
    _ensure_not_cancelled(page_s, "page")
    size_s = prompt_field("Size", default="10")
    _ensure_not_cancelled(size_s, "size")
    try:
        page = int(page_s)
        size = int(size_s)
    except ValueError:
        console.print("[red]Error: page and size must be integers.[/red]")
        raise click.Abort()
    try:
        client = get_memory_client()

        result = run_async_with_cleanup(client, client.list_async(page=page, size=size))
        
        # Display results in a table
        table = Table(title="Memories")
        table.add_column("ID", style="cyan")
        table.add_column("Name", style="magenta")
        table.add_column("Description", style="green")
        table.add_column("Status", style="yellow")
        table.add_column("Created At", style="blue")
        
        if result.listData:
            for memory in result.listData:
                table.add_row(
                    memory.id or "",
                    memory.name or "",
                    (memory.description or "")[:50],
                    memory.status or "",
                    str(memory.created_at) if memory.created_at else "",
                )
        
        console.print(table)
        console.print(f"\n[dim]Page {result.page} of {result.totalPage} (Total: {result.totalItem})[/dim]")
        
    except Exception as e:
        console.print(f"[red]Error: Failed to list memories: {e}[/red]")
        raise click.Abort()


