@memory_group.command(name="delete")
@click.argument("memory-id", required=False, default=None)
@click.option("--yes", "-y", is_flag=True, help="Skip confirmation")
def delete_memory(memory_id: Optional[str], yes: bool) -> None:
    """Delete a memory by ID.

    Examples:
        greennode memory delete memory-123
        greennode memory delete memory-123 --yes
        greennode memory delete   # interactive mode
    """
    memory_id = prompt_if_missing(memory_id, "Memory ID")
    _ensure_not_cancelled(memory_id, "memory_id")
