@records_group.command(name="generate")
@click.argument("memory-id", required=False, default=None)
@click.option(
    "--long-term-memory-strategy-id",
    "--strategy-id",
    "long_term_memory_strategy_id",
    required=False,
    default=None,
    help="Long-term memory strategy ID",
)
@click.option(
    "--from-session",
    is_flag=True,
    help="Generate from session (requires --actor-id and --session-id)",
)
@click.option("--actor-id", help="Actor ID (required for --from-session; optional for --from-content)")
@click.option("--session-id", help="Session ID (required for --from-session; optional for --from-content)")
@click.option("--content", "-c", multiple=True, help="Content messages (for --from-content)")
@click.option("--file", "-f", type=click.File("r"), help="File containing JSON messages")
def generate_memory_records(
    memory_id: Optional[str],
    long_term_memory_strategy_id: Optional[str],
    from_session: bool,
    actor_id: Optional[str],
    session_id: Optional[str],
    content: tuple,
    file: Optional[click.File],
) -> None:
    """Generate memory records from session or content.

    Examples:
        greennode memory records generate memory-123 --strategy-id strat-1 --from-session --actor-id actor-1 --session-id session-1
        greennode memory records generate memory-123 --strategy-id strat-1 -c '{"role":"user","content":"Hello"}'
        greennode memory records generate   # interactive mode
    """
    memory_id = prompt_if_missing(memory_id, "Memory ID")
    _ensure_not_cancelled(memory_id, "memory_id")
    long_term_memory_strategy_id = prompt_if_missing(long_term_memory_strategy_id, "Long-term memory strategy ID")
    _ensure_not_cancelled(long_term_memory_strategy_id, "long_term_memory_strategy_id")
    try:
        client = get_memory_client()

        if from_session:
            actor_id = prompt_if_missing(actor_id, "Actor ID")
            _ensure_not_cancelled(actor_id, "actor_id")
            session_id = prompt_if_missing(session_id, "Session ID")
            _ensure_not_cancelled(session_id, "session_id")

            run_async_with_cleanup(
                client,
                client.generate_memory_records_from_session_async(
                    id=memory_id,
                    actorId=actor_id,
                    sessionId=session_id,
                    longTermMemoryStrategyId=long_term_memory_strategy_id,
                )
            )

            console.print("[green]✓ Memory records generated from session[/green]")
        else:
            if not content and not file:
                content_val = prompt_field("Content (JSON message, e.g. {\"role\":\"user\",\"content\":\"Hello\"})", default="")
                _ensure_not_cancelled(content_val, "content")
                content = (content_val,)
            messages = []
            for c in content:
                try:
                    msg = json.loads(c) if isinstance(c, str) else c
                    messages.append(ChatMessage(**msg))
                except Exception as e:
                    console.print(f"[red]Error: Invalid JSON in content: {e}[/red]")
                    raise click.Abort()
            if file:
                try:
                    file_data = json.load(file)
                    if isinstance(file_data, list):
                        messages.extend([ChatMessage(**msg) for msg in file_data])
                    else:
                        messages.append(ChatMessage(**file_data))
                except Exception as e:
                    console.print(f"[red]Error: Invalid JSON in file: {e}[/red]")
                    raise click.Abort()
            if not messages:
                console.print("[red]Error: No content provided[/red]")
                raise click.Abort()

            request = MemoryRecordGenerateFromContentRequest(chat_messages=messages)
            kwargs: Any = {
                "id": memory_id,
                "longTermMemoryStrategyId": long_term_memory_strategy_id,
                "request": request,
            }
            if actor_id is not None:
                kwargs["actorId"] = actor_id
            if session_id is not None:
                kwargs["sessionId"] = session_id

            run_async_with_cleanup(client, client.generate_memory_records_from_content_async(**kwargs))

            console.print(
                f"[green]✓ Generated memory records from {len(messages)} message(s)[/green]"
            )

    except Exception as e:
        console.print(f"[red]Error: Failed to generate memory records: {e}[/red]")
        raise click.Abort()


